// Dynamic update via JS for theme switching:
export function syncThemeColor(isDark: boolean) {
  const metas = document.querySelectorAll('meta[name="theme-color"]');
  metas.forEach((m) => {
    const matches = m.getAttribute('media')?.includes(isDark ? 'dark' : 'light');
    if (matches) (m as HTMLMetaElement).content = isDark ? '#0a0a0a' : '#ffffff';
  });
}

