import { useEffect, useState } from 'react';

export function ActionToast({ message, actionLabel, onAction, onDismiss }: { message: string; actionLabel?: string; onAction?: () => void; onDismiss: () => void }) {
  useEffect(() => {
    const t = setTimeout(onDismiss, actionLabel ? 10000 : 4000);
    return () => clearTimeout(t);
  }, [actionLabel, onDismiss]);

  return (
    <div role="alert" className="flex items-center gap-3 rounded bg-neutral-900 text-white px-4 py-3 shadow-lg">
      <span className="flex-1 text-sm">{message}</span>
      {actionLabel && (
        <button onClick={() => { onAction?.(); onDismiss(); }} className="min-h-9 px-3 text-sm font-medium underline">{actionLabel}</button>
      )}
    </div>
  );
}

